// src/App.js - With Collapsible Sidebar & Your Design
import React, { useState, useEffect } from 'react';
import { Activity, Users, FlaskConical, History, LayoutDashboard, ChevronRight, CheckSquare, Menu, X, LogOut } from 'lucide-react';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import EligibilityChecker from './components/EligibilityChecker';
import PatientsManager from './components/PatientsManager';
import TrialsManager from './components/TrialsManager';
import { login as apiLogin, getCurrentUser } from './services/authService';
import { getChecks } from './services/apiService';

const App = () => {
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [token, setToken] = useState(null);
  const [userEmail, setUserEmail] = useState('');
  const [userName, setUserName] = useState('');
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);

  const handleLogin = async ({ email, password }) => {
    try {
      console.log('Attempting login for:', email);
      const data = await apiLogin(email, password);
      console.log('Login successful, token received:', data.access_token.substring(0, 20) + '...');
      setToken(data.access_token);
      setUserEmail(email);
      localStorage.setItem('authToken', data.access_token);
      localStorage.setItem('userEmail', email);
      return { success: true };
    } catch (e) {
      console.error('Login failed:', e);
      return { 
        success: false, 
        error: e.message || 'Unknown error occurred' 
      };
    }
  };

  const handleLogout = () => {
    console.log('Logging out');
    setToken(null);
    setUserEmail('');
    setUserName('');
    localStorage.removeItem('authToken');
    localStorage.removeItem('userEmail');
    setSelectedIndex(0);
  };

  useEffect(() => {
    const t = localStorage.getItem('authToken');
    const email = localStorage.getItem('userEmail');
    if (t) {
      console.log('Found stored token, attempting auto-login');
      setToken(t);
      if (email) setUserEmail(email);
    }
  }, []);

  useEffect(() => {
    if (!token) return;
    console.log('Fetching current user with token:', token.substring(0, 20) + '...');
    getCurrentUser(token)
      .then((u) => {
        console.log('Current user loaded:', u);
        setUserEmail(u.email);
        setUserName(u.name);
      })
      .catch((e) => {
        console.error('getCurrentUser failed:', e);
        if (e.message.includes('401') || e.message.includes('Unauthorized')) {
          console.log('Token appears to be invalid, clearing auth state');
          handleLogout();
        }
      });
  }, [token]);

  if (!token) {
    return <Login onLogin={handleLogin} />;
  }

  const styles = {
    container: {
      display: 'flex',
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0b0c0e 0%, #1e293b 50%, #0f172a 100%)',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
    },
    nav: {
      width: sidebarCollapsed ? '80px' : '280px',
      background: 'linear-gradient(180deg, #1e293b 0%, #0f172a 100%)',
      color: 'white',
      padding: sidebarCollapsed ? '24px 12px' : '32px 24px',
      boxShadow: '4px 0 24px rgba(0,0,0,0.3)',
      borderRight: '1px solid rgba(100,116,139,0.3)',
      transition: 'all 0.3s ease',
      position: 'relative'
    },
    collapseButton: {
      position: 'absolute',
      top: '20px',
      right: '-16px',
      width: '32px',
      height: '32px',
      borderRadius: '50%',
      background: 'linear-gradient(135deg, #22d3ee 0%, #1de12d 100%)',
      border: 'none',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      cursor: 'pointer',
      boxShadow: '0 4px 12px rgba(34, 211, 238, 0.4)',
      zIndex: 10,
      transition: 'transform 0.3s ease'
    },
    logo: {
      marginBottom: sidebarCollapsed ? '32px' : '48px',
      textAlign: sidebarCollapsed ? 'center' : 'left',
      transition: 'all 0.3s ease'
    },
    logoTitle: {
      fontSize: sidebarCollapsed ? '20px' : '28px',
      fontWeight: '800',
      background: 'linear-gradient(135deg, #22d3ee 0%, #3b82f6 100%)',
      WebkitBackgroundClip: 'text',
      WebkitTextFillColor: 'transparent',
      backgroundClip: 'text',
      marginBottom: '4px',
      transition: 'all 0.3s ease'
    },
    logoSubtitle: {
      color: '#94a3b8',
      fontSize: '14px',
      opacity: sidebarCollapsed ? 0 : 1,
      height: sidebarCollapsed ? '0' : 'auto',
      overflow: 'hidden',
      transition: 'all 0.3s ease'
    },
    navList: {
      listStyle: 'none',
      padding: 0,
      margin: 0,
    },
    navItem: {
      marginBottom: '12px',
    },
    main: {
      flex: 1,
      overflowY: 'auto',
      transition: 'all 0.3s ease'
    },
    userInfo: {
      marginTop: 'auto',
      paddingTop: '24px',
      borderTop: '1px solid rgba(100,116,139,0.3)',
      color: '#94a3b8',
      fontSize: '14px',
      transition: 'all 0.3s ease'
    },
    logoutButton: {
      marginTop: '12px',
      width: '100%',
      padding: '12px',
      background: 'rgba(239, 68, 68, 0.2)',
      border: '1px solid rgba(239, 68, 68, 0.3)',
      borderRadius: '12px',
      color: '#fca5a5',
      fontSize: '14px',
      fontWeight: '600',
      cursor: 'pointer',
      transition: 'all 0.3s ease',
      display: 'flex',
      alignItems: 'center',
      justifyContent: sidebarCollapsed ? 'center' : 'flex-start',
      gap: '8px'
    }
  };

  const navItems = [
    { icon: LayoutDashboard, label: 'Dashboard' },
    { icon: CheckSquare, label: 'Check Eligibility' },
    { icon: Users, label: 'Patients' },
    { icon: FlaskConical, label: 'Trials' },
    { icon: History, label: 'History' },
  ];

  const LeftNav = () => (
    <div style={styles.nav}>
      <button
        style={styles.collapseButton}
        onClick={() => setSidebarCollapsed(!sidebarCollapsed)}
        onMouseEnter={(e) => {
          e.target.style.transform = 'scale(1.1)';
        }}
        onMouseLeave={(e) => {
          e.target.style.transform = 'scale(1)';
        }}
      >
        {sidebarCollapsed ? <Menu size={18} color="white" /> : <X size={18} color="white" />}
      </button>

      <div style={styles.logo}>
        <div style={styles.logoTitle}>{sidebarCollapsed ? 'CS' : 'ClinSight'}</div>
        <div style={styles.logoSubtitle}>Clinical Dashboard</div>
      </div>

      <ul style={styles.navList}>
        {navItems.map((item, index) => {
          const Icon = item.icon;
          const isSelected = selectedIndex === index;
          const buttonStyle = {
            width: '100%',
            display: 'flex',
            alignItems: 'center',
            justifyContent: sidebarCollapsed ? 'center' : 'flex-start',
            gap: '12px',
            padding: sidebarCollapsed ? '16px' : '16px 20px',
            borderRadius: '16px',
            border: 'none',
            cursor: 'pointer',
            transition: 'all 0.3s ease',
            background: isSelected ? 'rgba(148,163,184,0.25)' : 'transparent',
            color: 'white',
            fontSize: '16px',
            fontWeight: '600',
            transform: isSelected ? 'scale(1.05)' : 'scale(1)',
            boxShadow: isSelected ? '0 8px 24px rgba(0,0,0,0.3)' : 'none',
            position: 'relative'
          };

          return (
            <li key={index} style={styles.navItem}>
              <button 
                style={buttonStyle} 
                onClick={() => setSelectedIndex(index)}
                onMouseEnter={(e) => {
                  if (!isSelected) {
                    e.target.style.background = 'rgba(148,163,184,0.1)';
                  }
                }}
                onMouseLeave={(e) => {
                  if (!isSelected) {
                    e.target.style.background = 'transparent';
                  }
                }}
              >
                <Icon size={20} />
                {!sidebarCollapsed && (
                  <>
                    <span style={{ flex: 1, textAlign: 'left' }}>{item.label}</span>
                    {isSelected && <ChevronRight size={16} />}
                  </>
                )}
              </button>
            </li>
          );
        })}
      </ul>

      <div style={styles.userInfo}>
        {!sidebarCollapsed && (
          <>
            <div style={{ fontWeight: '600', color: 'white', marginBottom: '4px' }}>
              {userName || 'User'}
            </div>
            <div style={{ fontSize: '12px' }}>{userEmail}</div>
          </>
        )}
        <button
          style={styles.logoutButton}
          onClick={handleLogout}
          onMouseEnter={(e) => {
            e.target.style.background = 'rgba(239, 68, 68, 0.3)';
          }}
          onMouseLeave={(e) => {
            e.target.style.background = 'rgba(239, 68, 68, 0.2)';
          }}
        >
          <LogOut size={18} />
          {!sidebarCollapsed && 'Logout'}
        </button>
      </div>
    </div>
  );

  const HistoryPage = () => {
    const [checks, setChecks] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
      getChecks(token)
        .then((data) => {
          setChecks(data);
          setLoading(false);
        })
        .catch((e) => {
          console.error('Error loading checks:', e);
          setLoading(false);
        });
    }, []);

    if (loading) return <div style={{ color: 'white', padding: '40px' }}>Loading history...</div>;

    return (
      <div style={{ padding: '40px', color: 'white' }}>
        <h1 style={{ fontSize: '48px', fontWeight: '800', marginBottom: '40px' }}>
          Eligibility History
        </h1>
        {checks.length === 0 ? (
          <div style={{
            background: 'rgba(30, 41, 59, 0.6)',
            padding: '40px',
            borderRadius: '24px',
            textAlign: 'center',
            color: '#94a3b8'
          }}>
            No checks yet. Run your first eligibility check!
          </div>
        ) : (
          checks.map((c) => (
            <div key={c.id} style={{
              background: 'rgba(30, 41, 59, 0.6)',
              padding: '24px',
              borderRadius: '16px',
              marginBottom: '16px',
              border: '1px solid rgba(100,116,139,0.3)'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <div style={{ fontSize: '20px', fontWeight: '700', marginBottom: '8px' }}>
                    Check #{c.id}
                  </div>
                  <div style={{ color: '#94a3b8' }}>
                    Status: {c.status} • Score: {(c.overall_score * 100).toFixed(1)}% • Confidence: {c.confidence_score.toFixed(1)}%
                  </div>
                </div>
                <div style={{
                  padding: '8px 16px',
                  borderRadius: '12px',
                  background: c.status === 'eligible' ? 'rgba(16, 185, 129, 0.2)' : 'rgba(239, 68, 68, 0.2)',
                  color: c.status === 'eligible' ? '#10b981' : '#ef4444',
                  fontWeight: '700',
                  textTransform: 'uppercase'
                }}>
                  {c.status}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    );
  };

  const pages = [
    <Dashboard key="dashboard" token={token} />,
    <EligibilityChecker key="eligibility" token={token} />,
    <PatientsManager key="patients" token={token} />,
    <TrialsManager key="trials" token={token} />,
    <HistoryPage key="history" />,
  ];

  return (
    <div style={styles.container}>
      <LeftNav />
      <div style={styles.main}>{pages[selectedIndex]}</div>
    </div>
  );
};

export default App;
